/// requested access.
///
/// If the receiver denies access, it MUST respond with `PermissionDenied`
/// (-32009). The error data MAY include a `ResourceRequestParams` value
/// describing the access the caller would need to be granted for the
/// operation to succeed; see `PermissionDeniedErrorData` in
/// `types/errors.ts`.
///
/// After a successful `resourceRequest`, the caller MAY use the corresponding
/// `resource*` commands (e.g. `resourceRead`, `resourceWrite`) to perform the
/// operation. Receivers MAY rescind access at any time by returning
/// `PermissionDenied` on subsequent operations.
///
/// Either `read`, `write`, or both SHOULD be set to `true`. A request with
/// neither flag set is treated as `read: true` by receivers.</summary>
public sealed record ResourceRequestParams
{
    /// <summary>Channel URI this command targets.</summary>
    public required string Channel { get; init; }

    /// <summary>Resource URI being requested. Typically a `file:` URI on the receiver's
    /// filesystem, but any URI scheme that the receiver mediates access to is
    /// allowed.</summary>
    public required string Uri { get; init; }

    /// <summary>Whether the caller needs read access to the resource.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public bool? Read { get; init; }

    /// <summary>Whether the caller needs write access to the resource.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public bool? Write { get; init; }
}

/// <summary>Result of the `resourceRequest` command.
///
/// An empty object on success.</summary>
public sealed record ResourceRequestResult
{
}

/// <summary>Creates a resource watcher on the receiver's filesystem.
///
/// The receiver allocates an `ahp-resource-watch:/&lt;id&gt;` channel URI and
/// returns it on {@link CreateResourceWatchResult.channel}. The caller then
/// [`subscribe`](./subscriptions)s to that channel to receive
/// `resourceWatch/changed` actions over the standard action envelope.
///
/// The watch lifecycle is tied to subscription: when every subscriber has
/// unsubscribed (or the underlying connection drops), the receiver MUST
/// release the watcher. There is no explicit dispose command — `unsubscribe`
/// is the only handle the caller needs.
///
/// Like the rest of the `resource*` family, `createResourceWatch` is
/// symmetrical and MAY be sent in either direction. Access is gated through
/// the same permission flow as `resourceRead`/`resourceWrite`.</summary>
public sealed record CreateResourceWatchParams
{
    /// <summary>Channel URI this command targets.</summary>
    public required string Channel { get; init; }

    /// <summary>URI to watch.</summary>
    public required string Uri { get; init; }

    /// <summary>If `true`, the receiver MUST report changes for descendants of `uri`.
    /// If `false` (default), only changes to `uri` itself — and, when `uri`
    /// is a directory, its direct children — are reported.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public bool? Recursive { get; init; }

    /// <summary>Glob patterns or paths relative to `uri` to exclude from reporting.
    /// Wrapped in `{ items }` for forward compatibility.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public JsonElement? Excludes { get; init; }

    /// <summary>Glob patterns or paths relative to `uri` to restrict reporting to.
    /// Omit to report every change under `uri` subject to `excludes`.
    /// Wrapped in `{ items }` for forward compatibility.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public JsonElement? Includes { get; init; }
}

/// <summary>Result of the `createResourceWatch` command.</summary>
public sealed record CreateResourceWatchResult
{
    /// <summary>Receiver-assigned watch channel URI (`ahp-resource-watch:/&lt;id&gt;`). The
    /// caller subscribes to this URI to start receiving change events and
    /// unsubscribes to release the watcher.</summary>
    public required string Channel { get; init; }
}

/// <summary>Fetches historical turns for a chat. Used for lazy loading of conversation
/// history.</summary>
public sealed record FetchTurnsParams
{
    /// <summary>Channel URI this command targets.</summary>
    public required string Channel { get; init; }

    /// <summary>Turn ID to fetch before (exclusive). Omit to fetch from the most recent turn.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Before { get; init; }

    /// <summary>Maximum number of turns to return. Server MAY impose its own upper bound.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? Limit { get; init; }
}

/// <summary>Result of the `fetchTurns` command.</summary>
public sealed record FetchTurnsResult
{
    /// <summary>The requested turns, ordered oldest-first</summary>
    public required List<Turn> Turns { get; init; }

    /// <summary>Whether more turns exist before the returned range</summary>
    public bool HasMore { get; init; }
}

/// <summary>Stop receiving updates for a channel.</summary>
public sealed record UnsubscribeParams
{
    /// <summary>Channel URI to unsubscribe from</summary>
    public required string Channel { get; init; }
}

/// <summary>Fire-and-forget action dispatch (write-ahead). The client applies actions
/// optimistically to local state and the server echoes them back as an
/// {@link ActionEnvelope} once accepted.
///
/// The client → server method is named `dispatchAction`; the server's reply
/// arrives on the server → client `action` notification (params:
/// {@link ActionEnvelope}).</summary>
public sealed record DispatchActionParams
{
    /// <summary>Channel URI this action targets</summary>
    public required string Channel { get; init; }

    /// <summary>Client sequence number</summary>
    public long ClientSeq { get; init; }

    /// <summary>The action to dispatch</summary>
    public required StateAction Action { get; init; }
}

/// <summary>Pushes a Bearer token for a protected resource. The `resource` field MUST
/// match a `ProtectedResourceMetadata.resource` value declared by an agent
/// in `AgentInfo.protectedResources`.
///
/// Tokens are delivered using [RFC 6750](https://datatracker.ietf.org/doc/html/rfc6750)
/// (Bearer Token Usage) semantics. The client obtains the token from the
/// authorization server(s) listed in the resource's metadata and pushes it
/// to the server via this command.</summary>
public sealed record AuthenticateParams
{
    /// <summary>Channel URI this command targets.</summary>
    public required string Channel { get; init; }

    /// <summary>The protected resource identifier. MUST match a `resource` value from
    /// `ProtectedResourceMetadata` declared in `AgentInfo.protectedResources`.</summary>
    public required string Resource { get; init; }

    /// <summary>Bearer token obtained from the resource's authorization server</summary>
    public required string Token { get; init; }
}

/// <summary>Result of the `authenticate` command.
///
/// An empty object on success. If the token is invalid or the resource is
/// unrecognized, the server MUST return a JSON-RPC error (e.g. `AuthRequired`
/// `-32007` or `InvalidParams` `-32602`).</summary>
public sealed record AuthenticateResult
{
}

/// <summary>Creates a new terminal on the server.
///
/// After creation, the client should subscribe to the terminal URI to receive
/// state updates. The server dispatches `root/terminalsChanged` to update the
/// root terminal list.</summary>
public sealed record CreateTerminalParams
{
    /// <summary>Channel URI this command targets.</summary>
    public required string Channel { get; init; }

    /// <summary>Initial owner of the terminal</summary>
    public required TerminalClaim Claim { get; init; }

    /// <summary>Human-readable terminal name</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Name { get; init; }

    /// <summary>Initial working directory URI</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Cwd { get; init; }

    /// <summary>Initial terminal width in columns</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? Cols { get; init; }

    /// <summary>Initial terminal height in rows</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? Rows { get; init; }
}

/// <summary>Disposes a terminal and kills its process if still running.
///
/// The server dispatches `root/terminalsChanged` to remove the terminal from
/// the root terminal list.</summary>
public sealed record DisposeTerminalParams
{
    /// <summary>Channel URI this command targets.</summary>
    public required string Channel { get; init; }
}

/// <summary>Iteratively resolves the session configuration schema. The client sends the
/// current partial session config and any user-filled metadata values. The server
/// returns a property schema describing what additional metadata is needed,
/// contextual to the current selections.
///
/// The client calls this command whenever the user changes a significant input
/// (e.g. picks a working directory, toggles a property). Each response returns
/// the full current property set (not a delta). The returned `values` contain
/// server-resolved defaults to pass to `createSession`.</summary>
public sealed record ResolveSessionConfigParams
{
    /// <summary>Channel URI this command targets.</summary>
    public required string Channel { get; init; }

    /// <summary>Agent provider ID</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Provider { get; init; }

    /// <summary>Working directory for the session</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? WorkingDirectory { get; init; }

    /// <summary>Current user-filled configuration values</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Config { get; init; }
}

/// <summary>Result of the `resolveSessionConfig` command.</summary>
public sealed record ResolveSessionConfigResult
{
    /// <summary>JSON Schema describing available configuration properties given the current context</summary>
    public required SessionConfigSchema Schema { get; init; }

    /// <summary>Current configuration values (echoed back with server-resolved defaults applied)</summary>
    public required Dictionary<string, JsonElement> Values { get; init; }
}

/// <summary>Queries the server for allowed values of a dynamic session config property.
///
/// Used when a property in the schema returned by `resolveSessionConfig` has
/// `enumDynamic: true`. The client sends a search query and receives matching
/// values with display metadata.</summary>
public sealed record SessionConfigCompletionsParams
{
    /// <summary>Channel URI this command targets.</summary>
    public required string Channel { get; init; }

    /// <summary>Agent provider ID</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Provider { get; init; }

    /// <summary>Working directory for the session</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? WorkingDirectory { get; init; }

    /// <summary>Current user-filled configuration values (provides context for the query)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Config { get; init; }

    /// <summary>Property id from the schema to query values for</summary>
    public required string Property { get; init; }

    /// <summary>Search filter text (empty or omitted returns default/recent values)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Query { get; init; }
}

/// <summary>Result of the `sessionConfigCompletions` command.</summary>
public sealed record SessionConfigCompletionsResult
{
    /// <summary>Matching value items</summary>
    public required List<SessionConfigValueItem> Items { get; init; }
}

/// <summary>A single value item returned by `sessionConfigCompletions`.</summary>
public sealed record SessionConfigValueItem
{
    /// <summary>The value to store in config</summary>
    public required string Value { get; init; }

    /// <summary>Human-readable display label</summary>
    public required string Label { get; init; }

    /// <summary>Optional secondary description</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Description { get; init; }
}

/// <summary>Requests completion items for a partially-typed input (e.g. a user message
/// the user is currently composing). Used to power `@`-mention pickers,
/// file/symbol references, and similar inline-completion experiences.
///
/// Servers SHOULD treat this command as best-effort and return promptly. The
/// client SHOULD debounce calls to avoid flooding the server with requests on
/// every keystroke.</summary>
public sealed record CompletionsParams
{
    /// <summary>Channel URI this command targets.</summary>
    public required string Channel { get; init; }

    /// <summary>What kind of completion is being requested.</summary>
    public CompletionItemKind Kind { get; init; }

    /// <summary>The complete text of the input being completed (e.g. the full user
    /// message text typed so far).</summary>
    public required string Text { get; init; }

    /// <summary>The character offset within `text` at which the completion is requested,
    /// measured in UTF-16 code units. MUST satisfy `0 &lt;= offset &lt;= text.length`.</summary>
    public long Offset { get; init; }
}

/// <summary>A single completion item returned by the `completions` command.
///
/// When the user accepts an item, the client SHOULD:
/// 1. Replace the range `[rangeStart, rangeEnd)` in the input with `insertText`
///    (or insert `insertText` at the cursor when the range is omitted).
/// 2. Associate the item's `attachment` with the resulting {@link Message}.</summary>
public sealed record CompletionItem
{
    /// <summary>The text inserted into the input when this item is accepted.</summary>
    public required string InsertText { get; init; }

    /// <summary>If defined, the start of the range in the input's `text` that is replaced
    /// by `insertText`. The range is the half-open interval
    /// `[rangeStart, rangeEnd)` of character offsets, measured in UTF-16 code
    /// units.
    ///
    /// When omitted, the client SHOULD insert `insertText` at the cursor.
    ///
    /// Note: this range refers to positions in the *current* input. The
    /// attachment's own `rangeStart`/`rangeEnd` (when present) refer to
    /// positions in the final {@link Message.text} after the item is
    /// accepted.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? RangeStart { get; init; }

    /// <summary>The end of the range in the input's `text` that is replaced by
    /// `insertText`. See {@link rangeStart}.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? RangeEnd { get; init; }

    /// <summary>The attachment associated with this completion item.</summary>
    public required MessageAttachment Attachment { get; init; }
}

/// <summary>Result of the `completions` command.</summary>
public sealed record CompletionsResult
{
    /// <summary>The completion items, in the order the server suggests displaying them.</summary>
    public required List<CompletionItem> Items { get; init; }
}

/// <summary>Invokes a server-defined {@link ChangesetOperation} against a changeset,
/// a single file, or a line range.
///
/// The server validates that `operationId` exists in the changeset's
/// current `operations` list and that the requested `target.kind` is
/// contained in the operation's `scopes`. Invalid combinations result in a
/// JSON-RPC error.
///
/// State changes resulting from invocation flow back through the normal
/// `changeset/*` action stream on the relevant changeset URIs. Clients
/// SHOULD NOT synthesise local optimistic changes for invocations unless
/// the server explicitly opts in via a future capability.</summary>
public sealed record InvokeChangesetOperationParams
{
    /// <summary>Channel URI this command targets.</summary>
    public required string Channel { get; init; }

    /// <summary>Matches {@link ChangesetOperation.id} from the changeset's `operations` list.</summary>
    public required string OperationId { get; init; }

    /// <summary>Target of the operation. Required iff the chosen scope is
    /// `'resource'` or `'range'`. Omit for changeset-scoped operations.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ChangesetOperationTarget? Target { get; init; }
}

/// <summary>Result of the {@link InvokeChangesetOperationParams | `invokeChangesetOperation`}
/// command.
///
/// Success is implicit: the server returns this result when it accepted
/// the operation. Failure is signalled by rejecting the JSON-RPC request
/// with an appropriate error code, not by any field on this result. The
/// operation MAY still produce subsequent failure feedback through the
/// {@link ChangesetStatusChangedAction | `changeset/statusChanged`} stream.</summary>
public sealed record InvokeChangesetOperationResult
{
    /// <summary>Optional human-readable message describing the result.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public StringOrMarkdown? Message { get; init; }

    /// <summary>Optional follow-up: a URI to open (e.g. a PR), a content ref, etc.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ChangesetOperationFollowUp? FollowUp { get; init; }
}

/// <summary>Optional follow-up surfaced by the server after an operation completes —
/// a {@link ContentRef} the client can fetch and display.
///
/// Set `external` to `true` to open the content in the user's preferred
/// external handler (e.g. browser); otherwise the client is expected to
/// surface it inline.</summary>
public sealed record ChangesetOperationFollowUp
{
    public required ContentRef Content { get; init; }

    /// <summary>When `true`, open in an external handler rather than inline.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public bool? External { get; init; }
}

